// Grocy gibt Array zurueck; n8n teilt es in einzelne Items auf
const chores = $input.all().map(i => i.json);
const todayStr = new Date().toDateString();
const today = new Date(todayStr);

const icons = {
  'Sauerteig':'🫙','Wisch':'🧹','Bad':'🚿','Toilette':'🚽',
  'Staub':'🌫️','Staubsaug':'🧹','Auto':'🚗','Pflanzen':'🌿',
  'Müll':'🗑️','Kühlschrank':'❄️','Küche':'🍳','Bett':'🛏️'
};
function icon(name) {
  for (const [k,v] of Object.entries(icons)) if (name.includes(k)) return v;
  return '📋';
}

const due = chores.filter(c => {
  if (!c.next_estimated_execution_time) return true;
  return new Date(new Date(c.next_estimated_execution_time).toDateString()) <= today;
}).sort((a,b) => {
  const da = a.next_estimated_execution_time ? new Date(a.next_estimated_execution_time) : new Date(0);
  const db = b.next_estimated_execution_time ? new Date(b.next_estimated_execution_time) : new Date(0);
  return da - db;
});

if (due.length === 0) {
  return [{ json: { message: '🏠 *Willkommen zuhause!*\n\n✅ Alles erledigt – keine fälligen Aufgaben heute!' } }];
}

const overdue = due.filter(c => {
  if (!c.next_estimated_execution_time) return true;
  return new Date(new Date(c.next_estimated_execution_time).toDateString()) < today;
});

const lines = due.map(c => {
  const d = c.next_estimated_execution_time
    ? Math.ceil((new Date(new Date(c.next_estimated_execution_time).toDateString()) - today) / 86400000)
    : -999;
  const badge = d < 0 ? ' _(' + Math.abs(d) + ' Tag' + (Math.abs(d)!==1?'e':'') + ' überfällig)_' : '';
  return icon(c.chore_name) + ' ' + c.chore_name + badge;
}).join('\n');

const overdueNote = overdue.length > 0 ? ' _(' + overdue.length + ' überfällig)_' : '';

return [{ json: {
  message: '🏠 *Willkommen zuhause!*\n📋 *' + due.length + ' Aufgabe' + (due.length!==1?'n':'') + ' heute*' + overdueNote + '\n\n' + lines
}}];

